INSERT INTO questions (question_text, choices, correct_answer, explanation, subject, topic, difficulty, exam_type) VALUES
('What is the scientific method?', '["A systematic process for investigating phenomena: observe, hypothesize, experiment, analyze, conclude", "A method for memorizing scientific facts", "A way to design experiments without testing hypotheses", "A set of laws governing scientific discoveries"]', 'A', 'The scientific method is a systematic approach: (1) observation, (2) question, (3) hypothesis, (4) experiment, (5) data analysis, (6) conclusion.', 'Science', 'Scientific Method', 'easy', 'secondary'),
('What is a hypothesis?', '["A testable prediction or explanation for a phenomenon", "A proven scientific theory", "The conclusion of an experiment", "An observation of a phenomenon"]', 'A', 'A hypothesis is a testable, falsifiable prediction or explanation for a scientific phenomenon. It is formulated before conducting experiments.', 'Science', 'Scientific Method', 'easy', 'secondary'),
('What does DNA stand for?', '["Deoxyribonucleic acid", "Diribonucleic acid", "Deoxyribonucleus acid", "Deoxyribose niacin acid"]', 'A', 'DNA stands for Deoxyribonucleic acid. It is the hereditary material in all living organisms, carrying genetic information.', 'Science', 'Biology', 'easy', 'secondary'),
('What is the powerhouse of the cell?', '["Mitochondria", "Nucleus", "Ribosome", "Golgi apparatus"]', 'A', 'Mitochondria are called the powerhouse of the cell because they produce ATP (adenosine triphosphate) through cellular respiration, providing energy for cell functions.', 'Science', 'Biology', 'easy', 'secondary'),
('What is the chemical formula for water?', '["H₂O", "H₂O₂", "HO", "HO₂"]', 'A', 'Water has the chemical formula H₂O, consisting of two hydrogen atoms covalently bonded to one oxygen atom.', 'Science', 'Chemistry', 'easy', 'secondary'),
('What is the process by which plants make food using sunlight?', '["Photosynthesis", "Cellular respiration", "Fermentation", "Transpiration"]', 'A', 'Photosynthesis is the process by which plants use sunlight, water (H₂O), and carbon dioxide (CO₂) to produce glucose and oxygen: 6CO₂ + 6H₂O + light → C₆H₁₂O₆ + 6O₂.', 'Science', 'Biology', 'easy', 'secondary'),
('What is the atomic number?', '["The number of protons in an atom''s nucleus", "The number of neutrons in an atom''s nucleus", "The total number of protons and neutrons", "The number of electrons in the outermost shell"]', 'A', 'The atomic number (Z) is the number of protons in an atom''s nucleus. It defines the element and determines its position on the periodic table.', 'Science', 'Chemistry', 'easy', 'secondary'),
('What is Newton''s Law of Universal Gravitation?', '["All objects with mass attract each other with a force proportional to their masses and inversely proportional to the square of the distance between them", "Objects fall at the same speed regardless of mass", "Gravity only applies to large objects like planets", "Gravitational force is constant everywhere"]', 'A', 'Newton''s Law of Universal Gravitation: F = Gm₁m₂/r². Every mass attracts every other mass; the force is proportional to masses and inversely proportional to the square of the distance.', 'Science', 'Physics', 'medium', 'secondary'),
('What is the term for the number of protons plus neutrons in an atom''s nucleus?', '["Mass number", "Atomic number", "Atomic mass unit", "Isotope number"]', 'A', 'The mass number is the total number of protons and neutrons (nucleons) in an atom''s nucleus. Mass number = atomic number + number of neutrons.', 'Science', 'Chemistry', 'easy', 'secondary'),
('What are isotopes?', '["Atoms of the same element with different numbers of neutrons", "Atoms of different elements with the same mass", "Ions with different charges", "Atoms with the same number of electrons and neutrons"]', 'A', 'Isotopes are atoms of the same element (same number of protons) but with different numbers of neutrons, giving them different mass numbers (e.g., Carbon-12 and Carbon-14).', 'Science', 'Chemistry', 'medium', 'secondary'),
('What is the function of hemoglobin?', '["To carry oxygen in red blood cells", "To fight infections", "To clot blood when injured", "To produce antibodies"]', 'A', 'Hemoglobin is the iron-containing protein in red blood cells that binds to oxygen in the lungs and transports it to cells throughout the body.', 'Science', 'Biology', 'medium', 'secondary'),
('What type of energy is stored in chemical bonds?', '["Chemical energy", "Thermal energy", "Mechanical energy", "Nuclear energy"]', 'A', 'Chemical energy is potential energy stored in the bonds between atoms in molecules. It is released during chemical reactions (e.g., burning fuel, cellular respiration).', 'Science', 'Chemistry', 'medium', 'secondary'),
('What is the term for the minimum energy required for a chemical reaction to occur?', '["Activation energy", "Potential energy", "Kinetic energy", "Bond energy"]', 'A', 'Activation energy is the minimum energy that must be supplied for a chemical reaction to start. Catalysts (like enzymes) lower the activation energy.', 'Science', 'Chemistry', 'medium', 'secondary'),
('What is the nervous system''s function?', '["To transmit signals between the brain and body, coordinating responses", "To pump blood throughout the body", "To filter waste from the blood", "To digest food"]', 'A', 'The nervous system (brain, spinal cord, nerves) receives information from the environment, processes it, and coordinates the body''s responses.', 'Science', 'Biology', 'easy', 'secondary'),
('What is the formula for density?', '["Density = Mass ÷ Volume", "Density = Volume ÷ Mass", "Density = Mass × Volume", "Density = Force ÷ Area"]', 'A', 'Density = Mass / Volume (D = m/V). It is the measure of mass per unit volume, typically in g/cm³ or kg/m³.', 'Science', 'Physics', 'easy', 'secondary'),
('What is the pH of pure water?', '["7 (neutral)", "1 (acidic)", "14 (basic)", "0 (highly acidic)"]', 'A', 'Pure water has a pH of 7, which is neutral. The pH scale ranges from 0-14, with 0-6 being acidic, 7 neutral, and 8-14 basic (alkaline).', 'Science', 'Chemistry', 'easy', 'secondary'),
('What is the role of ribosomes in a cell?', '["Protein synthesis", "DNA replication", "Energy production", "Cell division"]', 'A', 'Ribosomes are cellular organelles responsible for protein synthesis — they read mRNA and assemble amino acids into proteins.', 'Science', 'Biology', 'medium', 'secondary'),
('What is the difference between physical and chemical changes?', '["Physical changes don''t alter chemical composition; chemical changes create new substances", "Physical changes are permanent; chemical changes are temporary", "Physical changes are faster than chemical changes", "There is no fundamental difference"]', 'A', 'Physical changes alter shape/state but not chemical composition (cutting, melting). Chemical changes create new substances with different properties (burning, rusting).', 'Science', 'Chemistry', 'medium', 'secondary'),
('What is Archimedes'' Principle?', '["A body immersed in fluid experiences an upward buoyant force equal to the weight of fluid displaced", "Pressure in fluids increases with depth", "Fluids always flow from high to low pressure", "Objects float if their density is greater than water"]', 'A', 'Archimedes'' Principle: The buoyant force on an object equals the weight of the fluid it displaces. This explains why objects float or sink.', 'Science', 'Physics', 'medium', 'secondary'),
('What is the function of white blood cells?', '["To defend the body against infections and diseases", "To carry oxygen throughout the body", "To clot blood when cut", "To produce platelets"]', 'A', 'White blood cells (leukocytes) are part of the immune system, defending the body against bacteria, viruses, and other pathogens.', 'Science', 'Biology', 'easy', 'secondary'),
('What is the law of conservation of mass in chemistry?', '["Matter is neither created nor destroyed in a chemical reaction — total mass of reactants equals total mass of products", "Mass can be created from energy", "Solids always have greater mass than gases", "Chemical reactions always increase mass"]', 'A', 'The law of conservation of mass states that in a chemical reaction, the total mass of reactants equals the total mass of products — matter is conserved.', 'Science', 'Chemistry', 'medium', 'secondary'),
('What is the function of the endocrine system?', '["To produce and secrete hormones that regulate body functions", "To filter waste from the blood", "To transmit nerve signals", "To pump blood throughout the body"]', 'A', 'The endocrine system consists of glands (like the thyroid, pituitary, adrenal glands) that secrete hormones into the bloodstream to regulate growth, metabolism, and reproduction.', 'Science', 'Biology', 'medium', 'secondary'),
('What is the difference between ionic and covalent bonds?', '["Ionic bonds involve electron transfer; covalent bonds involve electron sharing", "Both involve electron transfer", "Both involve electron sharing", "Covalent bonds are found only in metals"]', 'A', 'Ionic bonds form by electron transfer between atoms with large electronegativity differences (e.g., NaCl). Covalent bonds form by electron sharing between atoms with similar electronegativities (e.g., H₂O).', 'Science', 'Chemistry', 'medium', 'secondary'),
('What is the term for an organism that makes its own food through photosynthesis?', '["Autotroph/Producer", "Heterotroph/Consumer", "Decomposer", "Parasite"]', 'A', 'Autotrophs (producers) make their own food using light energy (photosynthesis) or chemical energy (chemosynthesis). Plants are the main autotrophs in most food chains.', 'Science', 'Biology', 'easy', 'secondary'),
('What is the frequency of visible light compared to radio waves?', '["Visible light has higher frequency than radio waves", "Radio waves have higher frequency than visible light", "They have the same frequency", "Visible light has lower frequency than radio waves"]', 'A', 'The electromagnetic spectrum from lowest to highest frequency: radio waves < microwaves < infrared < visible light < UV < X-rays < gamma rays.', 'Science', 'Physics', 'medium', 'secondary'),
('What is a catalyst?', '["A substance that speeds up a chemical reaction without being consumed", "A substance that slows down a reaction", "A product of a chemical reaction", "A substance that increases activation energy"]', 'A', 'A catalyst increases the rate of a chemical reaction by lowering the activation energy, without being consumed in the process. Enzymes are biological catalysts.', 'Science', 'Chemistry', 'medium', 'secondary'),
('What is the process by which organisms break down glucose for energy in the absence of oxygen?', '["Anaerobic respiration (fermentation)", "Aerobic respiration", "Photosynthesis", "Transpiration"]', 'A', 'Anaerobic respiration (fermentation) breaks down glucose without oxygen, producing ATP plus lactic acid (in animals/bacteria) or ethanol and CO₂ (in yeast/plants).', 'Science', 'Biology', 'medium', 'secondary'),
('What is Bernoulli''s Principle?', '["As the speed of a fluid increases, its pressure decreases", "Pressure in fluids increases with depth", "Fluids always flow from low to high pressure", "Denser fluids always move faster"]', 'A', 'Bernoulli''s Principle states that an increase in fluid speed is accompanied by a decrease in pressure or potential energy. This explains airplane lift and how wings work.', 'Science', 'Physics', 'hard', 'secondary'),
('What is the term for organisms that feed on dead organic matter?', '["Decomposers", "Producers", "Primary consumers", "Secondary consumers"]', 'A', 'Decomposers (bacteria, fungi) break down dead organic matter, returning nutrients to the soil and completing the nutrient cycle.', 'Science', 'Biology', 'easy', 'secondary'),
('In a chemical equation, what must be the same on both sides?', '["Number of atoms of each element (Law of Conservation of Mass)", "Number of molecules", "Total number of bonds", "Volume of reactants and products"]', 'A', 'In a balanced chemical equation, the number of atoms of each element must be equal on both sides, reflecting the conservation of mass.', 'Science', 'Chemistry', 'easy', 'secondary'),
('What is the greenhouse gas most responsible for climate change?', '["Carbon dioxide (CO₂)", "Oxygen (O₂)", "Nitrogen (N₂)", "Hydrogen (H₂)"]', 'A', 'Carbon dioxide (CO₂) from burning fossil fuels is the primary anthropogenic greenhouse gas responsible for enhanced greenhouse effect and climate change.', 'Science', 'Earth Science', 'easy', 'secondary'),
('What is the term for a substance that donates protons (H⁺ ions) in a reaction?', '["Acid", "Base", "Salt", "Buffer"]', 'A', 'According to Brønsted-Lowry theory, an acid is a proton donor (donates H⁺ ions). A base is a proton acceptor.', 'Science', 'Chemistry', 'medium', 'secondary'),
('What is the immune system''s first line of defense against pathogens?', '["Skin and mucous membranes", "White blood cells", "Antibodies", "Fever"]', 'A', 'The first line of defense is physical and chemical barriers: skin prevents entry of pathogens; mucous membranes trap them; stomach acid kills many that are ingested.', 'Science', 'Biology', 'medium', 'secondary'),
('What is the term for a change in an organism''s DNA?', '["Mutation", "Evolution", "Adaptation", "Variation"]', 'A', 'A mutation is a change in an organism''s DNA sequence. Mutations can be caused by radiation, chemicals, or errors during DNA replication. They may be harmful, beneficial, or neutral.', 'Science', 'Biology', 'medium', 'secondary'),
('What does a concave mirror do to light?', '["Converges light to a focal point", "Diverges light outward", "Absorbs light completely", "Has no effect on light direction"]', 'A', 'A concave (converging) mirror curves inward, reflecting light rays to meet at a focal point in front of the mirror. Used in telescopes and solar concentrators.', 'Science', 'Physics', 'medium', 'secondary'),
('What is the term for the process of converting a liquid to a gas by heating?', '["Evaporation", "Condensation", "Sublimation", "Deposition"]', 'A', 'Evaporation is the process where a liquid changes to a gas (vapor) state when heated. Evaporation can occur at any temperature at the liquid''s surface.', 'Science', 'Chemistry', 'easy', 'secondary'),
('What is the cellular organelle that contains the cell''s genetic information?', '["Nucleus", "Mitochondria", "Ribosome", "Endoplasmic reticulum"]', 'A', 'The nucleus is the control center of the cell, containing DNA (the cell''s genetic information) enclosed in a nuclear membrane.', 'Science', 'Biology', 'easy', 'secondary'),
('What is the difference between mass and weight?', '["Mass is the amount of matter; weight is the force due to gravity acting on mass", "Mass changes with location; weight is constant", "They are the same physical property", "Weight is measured in kilograms; mass in newtons"]', 'A', 'Mass is the amount of matter in an object (constant everywhere, measured in kg). Weight is the gravitational force on an object (W = mg, varies with location, measured in Newtons).', 'Science', 'Physics', 'medium', 'secondary'),
('What is the role of the ozone layer?', '["Absorbs harmful ultraviolet (UV) radiation from the sun", "Produces oxygen for breathing", "Reflects sunlight to cool the Earth", "Filters carbon dioxide from the atmosphere"]', 'A', 'The ozone layer (stratosphere) absorbs 97-99% of the sun''s ultraviolet radiation, protecting living organisms from its harmful effects (skin cancer, DNA damage).', 'Science', 'Earth Science', 'easy', 'secondary'),
('What is a food chain?', '["A sequence showing how energy passes from one organism to another in an ecosystem", "A list of foods eaten by animals", "A cycle of nutrient recycling", "A web showing all feeding relationships"]', 'A', 'A food chain shows the linear sequence of energy transfer from producers (plants) through consumers to decomposers in an ecosystem.', 'Science', 'Biology', 'easy', 'secondary'),
('What is the difference between speed and velocity in physics?', '["Velocity is speed with direction (vector); speed is just magnitude (scalar)", "Speed includes direction; velocity does not", "Velocity is always greater than speed", "They are the same physical quantity"]', 'A', 'Speed is a scalar quantity (magnitude only). Velocity is a vector quantity with both magnitude and direction. An object can have constant speed but changing velocity (if it changes direction).', 'Science', 'Physics', 'medium', 'secondary'),
('What type of chemical reaction releases energy to the surroundings?', '["Exothermic reaction", "Endothermic reaction", "Neutralization reaction", "Decomposition reaction"]', 'A', 'Exothermic reactions release energy (usually as heat) to the surroundings, so products have less energy than reactants (e.g., combustion, respiration).', 'Science', 'Chemistry', 'medium', 'secondary'),
('What is the term for the process in which mRNA is used to build a protein?', '["Translation", "Transcription", "Replication", "Mutation"]', 'A', 'Translation is the process where ribosomes read mRNA codons and assemble amino acids into a protein. Transcription is the prior step of making mRNA from DNA.', 'Science', 'Biology', 'hard', 'secondary'),
('What is electromagnetism?', '["The relationship between electric currents and magnetic fields", "The study of static electricity only", "The attraction between charged objects", "The repulsion between magnets"]', 'A', 'Electromagnetism describes the interaction between electric currents/charges and magnetic fields. Electric currents produce magnetic fields (and vice versa).', 'Science', 'Physics', 'medium', 'secondary'),
('What is the difference between a physical property and a chemical property?', '["Physical properties can be observed without changing composition; chemical properties describe reactions that change composition", "Physical properties are more important than chemical properties", "Chemical properties can be measured without changing the substance", "They describe the same characteristics"]', 'A', 'Physical properties (color, density, melting point) can be observed without changing the substance''s composition. Chemical properties describe how a substance reacts with other substances.', 'Science', 'Chemistry', 'medium', 'secondary'),
('What is the role of enzymes in biological reactions?', '["To act as biological catalysts that speed up metabolic reactions", "To provide energy for reactions", "To be consumed during reactions", "To slow down harmful reactions"]', 'A', 'Enzymes are proteins that act as biological catalysts, speeding up metabolic reactions by lowering activation energy. They are highly specific and not consumed in reactions.', 'Science', 'Biology', 'medium', 'secondary'),
('What causes electric current to flow in a circuit?', '["A potential difference (voltage) across a conductor", "The resistance of the conductor", "The temperature of the conductor", "The length of the wire"]', 'A', 'Electric current flows in a circuit when there is a potential difference (voltage) to drive the flow of charge. Current = Voltage / Resistance (Ohm''s Law: I = V/R).', 'Science', 'Physics', 'medium', 'secondary'),
('What is the term for the process by which some organisms produce light?', '["Bioluminescence", "Phosphorescence", "Fluorescence", "Chemiluminescence"]', 'A', 'Bioluminescence is the production and emission of light by living organisms through chemical reactions (e.g., fireflies, deep-sea fish, some bacteria).', 'Science', 'Biology', 'hard', 'secondary'),
('What is the relationship between temperature and the state of matter?', '["Higher temperature generally changes matter from solid to liquid to gas", "Temperature has no effect on state", "Lower temperature makes matter gaseous", "Temperature only affects chemical changes"]', 'A', 'Temperature affects the state of matter: solids melt to liquids (melting point), liquids evaporate to gases (boiling point). Adding energy increases molecular motion.', 'Science', 'Chemistry', 'easy', 'secondary'),
('What is "homeostasis"?', '["The tendency of living organisms to maintain stable internal conditions despite external changes", "The process of cell division", "The movement of organisms toward food", "The balance between predator and prey populations"]', 'A', 'Homeostasis is the process by which living organisms maintain a stable internal environment (e.g., body temperature, blood sugar, pH) despite external changes.', 'Science', 'Biology', 'medium', 'secondary');
